mapper.select:
SELECT a.user_code AS "userCode", MAX(a.user_name) AS "userName", MAX(a.cpm) AS "cpm", MAX(a.wpm) AS "wpm", ROUND(AVG(a.accuracy)) AS "accuracy", COUNT(1) AS "recordCount" FROM ts_speed_record a WHERE a.status = '0'
AND a.mode = #{mode}
AND a.create_date >= #{beginDate}
AND a.create_date <= #{endDate}
GROUP BY a.user_code ORDER BY MAX(a.cpm) DESC
